mapper.select:
SELECT so.id, so.user_id, so.inventory_id, so.item_id, so.price, so.status, so.is_response_to_buy, so.target_buy_order_id, so.expire_time, so.created_at, so.updated_at, i.name as item_name, i.name_cn as item_name_cn, i.category as item_category, i.quality as item_quality, i.exterior as item_exterior, i.icon_url as item_icon_url, i.buff_price as item_buff_price, ui.name as inv_name, ui.icon_url as inv_icon_url, ui.exterior as inv_exterior, ui.paint_wear as inv_paint_wear, u.username, u.avatar FROM sell_order so LEFT JOIN item i ON so.item_id = i.id LEFT JOIN user_inventory ui ON so.inventory_id = ui.id LEFT JOIN sys_user u ON so.user_id = u.id WHERE so.status = 1
AND i.sub_category = #{category}
AND (i.exterior = #{exterior} OR ui.exterior = #{exterior})
AND i.quality = #{quality}
AND (i.name LIKE CONCAT('%', #{keyword}, '%') OR i.name_cn LIKE CONCAT('%', #{keyword}, '%') OR ui.name LIKE CONCAT('%', #{keyword}, '%'))
AND so.price >= #{minPrice}
AND so.price <= #{maxPrice}
ORDER BY
so.price ASC so.price DESC so.created_at DESC so.created_at ASC so.created_at DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM sell_order so
LEFT JOIN item i ON so.item_id = i.id
LEFT JOIN user_inventory ui ON so.inventory_id = ui.id
WHERE so.status = 1

    AND i.sub_category = #{category}


    AND (i.exterior = #{exterior} OR ui.exterior = #{exterior})


    AND i.quality = #{quality}


    AND (i.name LIKE CONCAT('%', #{keyword}, '%') OR i.name_cn LIKE CONCAT('%', #{keyword}, '%') OR ui.name LIKE CONCAT('%', #{keyword}, '%'))


    AND so.price >= #{minPrice}


    AND so.price <= #{maxPrice}
